  ('bookkeeper-moex-01674', 'bookkeeper', 'bookkeeper-moex-101-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國記帳士法之規定，直轄市及縣（市）記帳士公會，應由該行政區域內開業記帳士多少人以上發 起組織之？', '["十人", "三十人", "五十人", "一百人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "acbcc7ff0a91", "answer_pdf_sha1": "82fc343096c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
